// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import {IERC20} from "./interfaces/IERC20.sol";
import {IXcm} from "./interfaces/IXcm.sol";
import {ISystem} from "./interfaces/ISystem.sol";
import {ReentrancyGuard} from "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/// @title TesseractSwap — Polkadot-native constant-product AMM
/// @notice Pools use BLAKE2-256 IDs (via System precompile) instead of keccak256.
///         Tokens are XC-20 / Assets pallet entries exposed as ERC-20 precompiles.
///         swapAndBridgeXCM executes swap + cross-chain bridge in one atomic tx.
contract TesseractSwap is ReentrancyGuard {
    // ──────────────────── State ────────────────────

    address public immutable xcmPrecompile;
    address public immutable systemPrecompile;
    address public owner;

    // assetId → ERC-20 precompile address
    mapping(uint32 => address) public assetPrecompile;

    struct Pool {
        uint256 reserveA;
        uint256 reserveB;
        uint256 totalShares;
        mapping(address => uint256) shares;
    }

    // poolId (BLAKE2-256 of sorted assetIds) → Pool
    mapping(bytes32 => Pool) public pools;

    modifier onlyOwner() {
        require(msg.sender == owner, "TesseractSwap: not owner");
        _;
    }

    // ──────────────────── Events ───────────────────

    event AssetRegistered(uint32 indexed assetId, address precompileAddr);
    event LiquidityAdded(address indexed provider, bytes32 indexed poolId, uint256 shares);
    event LiquidityRemoved(address indexed provider, bytes32 indexed poolId, uint256 shares);
    event Swap(address indexed sender, uint32 assetIdIn, uint32 assetIdOut, uint256 amountIn, uint256 amountOut);
    event BridgeXCM(address indexed sender, uint32 assetIdOut, uint256 amountOut, bytes xcmDestination);

    // ──────────────────── Constructor ──────────────

    constructor(address _xcmPrecompile, address _systemPrecompile) {
        xcmPrecompile = _xcmPrecompile;
        systemPrecompile = _systemPrecompile;
        owner = msg.sender;
    }

    // ──────────────────── Asset Registration ───────

    function registerAsset(uint32 assetId, address precompileAddr) external onlyOwner {
        require(precompileAddr != address(0), "TesseractSwap: zero address");
        assetPrecompile[assetId] = precompileAddr;
        emit AssetRegistered(assetId, precompileAddr);
    }

    // ──────────────────── Pool ID (BLAKE2) ─────────

    /// @notice Derives pool ID using Polkadot's native BLAKE2-256 hash
    /// @dev This is a genuine Polkadot-native design. Ethereum has no BLAKE2 precompile.
    function getPoolId(uint32 assetA, uint32 assetB) public view returns (bytes32) {
        (uint32 sorted0, uint32 sorted1) = assetA < assetB ? (assetA, assetB) : (assetB, assetA);
        return ISystem(systemPrecompile).hashBlake256(
            abi.encodePacked(sorted0, sorted1)
        );
    }

    // ──────────────────── Liquidity ────────────────

    function addLiquidity(
        uint32 assetA,
        uint32 assetB,
        uint256 amountA,
        uint256 amountB
    ) external nonReentrant returns (uint256 shares) {
        require(amountA > 0 && amountB > 0, "TesseractSwap: zero amount");
        address tokenA = assetPrecompile[assetA];
        address tokenB = assetPrecompile[assetB];
        require(tokenA != address(0) && tokenB != address(0), "TesseractSwap: unregistered asset");

        bytes32 poolId = getPoolId(assetA, assetB);
        Pool storage pool = pools[poolId];

        // Ensure consistent token ordering
        (address token0, address token1, uint256 amount0, uint256 amount1) =
            assetA < assetB
                ? (tokenA, tokenB, amountA, amountB)
                : (tokenB, tokenA, amountB, amountA);

        // Pull tokens
        IERC20(token0).transferFrom(msg.sender, address(this), amount0);
        IERC20(token1).transferFrom(msg.sender, address(this), amount1);

        // Calculate shares
        if (pool.totalShares == 0) {
            shares = _sqrt(amount0 * amount1);
            require(shares > 0, "TesseractSwap: insufficient initial liquidity");
        } else {
            shares = _min(
                (amount0 * pool.totalShares) / pool.reserveA,
                (amount1 * pool.totalShares) / pool.reserveB
            );
        }

        pool.reserveA += amount0;
        pool.reserveB += amount1;
        pool.totalShares += shares;
        pool.shares[msg.sender] += shares;

        emit LiquidityAdded(msg.sender, poolId, shares);
    }

    function removeLiquidity(
        uint32 assetA,
        uint32 assetB,
        uint256 shares
    ) external nonReentrant returns (uint256 amountA, uint256 amountB) {
        bytes32 poolId = getPoolId(assetA, assetB);
        Pool storage pool = pools[poolId];

        require(pool.shares[msg.sender] >= shares, "TesseractSwap: insufficient shares");
        require(pool.totalShares > 0, "TesseractSwap: empty pool");

        amountA = (shares * pool.reserveA) / pool.totalShares;
        amountB = (shares * pool.reserveB) / pool.totalShares;

        pool.shares[msg.sender] -= shares;
        pool.totalShares -= shares;
        pool.reserveA -= amountA;
        pool.reserveB -= amountB;

        // Return tokens in sorted order
        (address token0, address token1) = _getSortedTokens(assetA, assetB);
        IERC20(token0).transfer(msg.sender, amountA);
        IERC20(token1).transfer(msg.sender, amountB);

        emit LiquidityRemoved(msg.sender, poolId, shares);
    }

    // ──────────────────── Swap ─────────────────────

    function swap(
        uint32 assetIdIn,
        uint32 assetIdOut,
        uint256 amountIn,
        uint256 minAmountOut
    ) public nonReentrant returns (uint256 amountOut) {
        return _swap(msg.sender, assetIdIn, assetIdOut, amountIn, minAmountOut, msg.sender);
    }

    // ──────────────────── Swap + XCM Bridge ────────

    /// @notice Atomic swap followed by XCM cross-chain bridge — the headline Polkadot-native function.
    /// @dev weighMessage MUST be called before execute to prevent asset trapping on destination.
    function swapAndBridgeXCM(
        uint32 assetIdIn,
        uint32 assetIdOut,
        uint256 amountIn,
        uint256 minAmountOut,
        bytes calldata xcmDestination,
        bytes calldata xcmMessage
    ) external nonReentrant returns (uint256 amountOut) {
        // Output stays in contract for XCM dispatch since recipient is address(this)
        amountOut = _swap(msg.sender, assetIdIn, assetIdOut, amountIn, minAmountOut, address(this));

        // XCM bridge: weigh first, then execute
        IXcm.Weight memory w = IXcm(xcmPrecompile).weighMessage(xcmMessage);
        IXcm(xcmPrecompile).execute(xcmMessage, w);

        emit BridgeXCM(msg.sender, assetIdOut, amountOut, xcmDestination);
    }

    // ──────────────────── View Helpers ─────────────

    function getPoolShares(bytes32 poolId, address user) external view returns (uint256) {
        return pools[poolId].shares[user];
    }

    function getReserves(uint32 assetA, uint32 assetB) external view returns (uint256 reserveA, uint256 reserveB) {
        bytes32 poolId = getPoolId(assetA, assetB);
        reserveA = pools[poolId].reserveA;
        reserveB = pools[poolId].reserveB;
    }

    // ──────────────────── Internal ─────────────────

    function _swap(
        address user,
        uint32 assetIdIn,
        uint32 assetIdOut,
        uint256 amountIn,
        uint256 minAmountOut,
        address recipient
    ) internal returns (uint256 amountOut) {
        require(amountIn > 0, "TesseractSwap: zero input");
        address tokenIn = assetPrecompile[assetIdIn];
        address tokenOut = assetPrecompile[assetIdOut];
        require(tokenIn != address(0) && tokenOut != address(0), "TesseractSwap: unregistered");

        bytes32 poolId = getPoolId(assetIdIn, assetIdOut);
        Pool storage pool = pools[poolId];

        bool inIsFirst = assetIdIn < assetIdOut;
        uint256 reserveIn = inIsFirst ? pool.reserveA : pool.reserveB;
        uint256 reserveOut = inIsFirst ? pool.reserveB : pool.reserveA;

        require(reserveIn > 0 && reserveOut > 0, "TesseractSwap: no liquidity");

        uint256 amountInWithFee = amountIn * 997;
        amountOut = (amountInWithFee * reserveOut) / (reserveIn * 1000 + amountInWithFee);
        require(amountOut >= minAmountOut, "TesseractSwap: slippage exceeded");

        IERC20(tokenIn).transferFrom(user, address(this), amountIn);
        if (recipient != address(this)) {
            IERC20(tokenOut).transfer(recipient, amountOut);
        }

        if (inIsFirst) {
            pool.reserveA += amountIn;
            pool.reserveB -= amountOut;
        } else {
            pool.reserveB += amountIn;
            pool.reserveA -= amountOut;
        }

        emit Swap(user, assetIdIn, assetIdOut, amountIn, amountOut);
    }

    function _getSortedTokens(uint32 assetA, uint32 assetB) internal view returns (address, address) {
        return assetA < assetB
            ? (assetPrecompile[assetA], assetPrecompile[assetB])
            : (assetPrecompile[assetB], assetPrecompile[assetA]);
    }

    function _sqrt(uint256 y) internal pure returns (uint256 z) {
        if (y > 3) {
            z = y;
            uint256 x = y / 2 + 1;
            while (x < z) { z = x; x = (y / x + x) / 2; }
        } else if (y != 0) {
            z = 1;
        }
    }

    function _min(uint256 a, uint256 b) internal pure returns (uint256) {
        return a < b ? a : b;
    }
}

