// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import {IERC20} from "./interfaces/IERC20.sol";
import {IXcm} from "./interfaces/IXcm.sol";
import {ISystem} from "./interfaces/ISystem.sol";
import {ITesseractCompute} from "./interfaces/ITesseractCompute.sol";
import {ReentrancyGuard} from "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/// @title TesseractVault — ERC-4626 yield vault with XCM rebalancing
/// @notice Accepts one underlying ERC-20 asset, issues vault shares.
///         rebalance() does: weight guard → cross-VM call to PVM → XCM execution.
///         This single function demonstrates the entire Polkadot smart contract stack.
contract TesseractVault is ReentrancyGuard {
    // ──────────────────── State ────────────────────

    IERC20 public immutable asset;
    address public immutable xcmPrecompile;
    address public immutable systemPrecompile;
    address public computeContract;
    address public owner;

    string public name;
    string public symbol;
    uint8 public constant decimals = 10; // Match underlying asset

    uint256 public totalAssets;
    uint256 public totalSupply;
    mapping(address => uint256) public balanceOf;

    modifier onlyOwner() {
        require(msg.sender == owner, "TesseractVault: not owner");
        _;
    }

    // ──────────────────── Events ───────────────────

    event Deposit(address indexed sender, address indexed receiver, uint256 assets, uint256 shares);
    event Withdraw(address indexed sender, address indexed receiver, uint256 assets, uint256 shares);
    event Rebalanced(uint64 bestStrategyIndex, bytes xcmMessage, uint64 refTime, uint64 proofSize);
    event ComputeContractSet(address computeContract);

    // ──────────────────── Constructor ──────────────

    constructor(
        address _asset,
        address _xcmPrecompile,
        address _systemPrecompile,
        address _computeContract,
        string memory _name,
        string memory _symbol
    ) {
        asset = IERC20(_asset);
        xcmPrecompile = _xcmPrecompile;
        systemPrecompile = _systemPrecompile;
        computeContract = _computeContract;
        name = _name;
        symbol = _symbol;
        owner = msg.sender;
    }

    // ──────────────────── ERC-4626: Deposit ────────

    function deposit(uint256 assets, address receiver)
        external nonReentrant returns (uint256 shares)
    {
        require(assets > 0, "TesseractVault: zero deposit");

        shares = totalSupply == 0
            ? assets
            : (assets * totalSupply) / totalAssets;

        require(shares > 0, "TesseractVault: zero shares");

        asset.transferFrom(msg.sender, address(this), assets);
        totalAssets += assets;
        totalSupply += shares;
        balanceOf[receiver] += shares;

        emit Deposit(msg.sender, receiver, assets, shares);
    }

    // ──────────────────── ERC-4626: Withdraw ───────

    function withdraw(uint256 shares, address receiver)
        external nonReentrant returns (uint256 assets)
    {
        require(shares > 0, "TesseractVault: zero shares");
        require(balanceOf[msg.sender] >= shares, "TesseractVault: insufficient shares");

        assets = (shares * totalAssets) / totalSupply;
        require(assets > 0, "TesseractVault: zero assets");

        balanceOf[msg.sender] -= shares;
        totalSupply -= shares;
        totalAssets -= assets;

        asset.transfer(receiver, assets);

        emit Withdraw(msg.sender, receiver, assets, shares);
    }

    // ──────────────────── ERC-4626: Preview ────────

    function previewDeposit(uint256 assets) external view returns (uint256) {
        if (totalSupply == 0) return assets;
        return (assets * totalSupply) / totalAssets;
    }

    function previewWithdraw(uint256 shares) external view returns (uint256) {
        if (totalSupply == 0) return 0;
        return (shares * totalAssets) / totalSupply;
    }

    function convertToShares(uint256 assets) external view returns (uint256) {
        if (totalSupply == 0) return assets;
        return (assets * totalSupply) / totalAssets;
    }

    function convertToAssets(uint256 shares) external view returns (uint256) {
        if (totalSupply == 0) return 0;
        return (shares * totalAssets) / totalSupply;
    }

    // ──────────────────── Rebalance (Cross-VM + XCM) ──────

    /// @notice Full-stack Polkadot demo: weight guard → cross-VM to PVM → XCM execute
    /// @dev This single function touches EVM, PVM, and XCM in one transaction.
    function rebalance(uint64[] calldata strategyAprs, bytes calldata xcmMessage)
        external onlyOwner nonReentrant
    {
        // Step 1 — WEIGHT GUARD (Polkadot-native safety check)
        // Ethereum has no equivalent concept. Polkadot's weight system can run
        // out of compute mid-block. This ensures enough headroom before XCM.
        (uint64 refTime, ) = ISystem(systemPrecompile).weightLeft();
        require(refTime > 5_000_000_000, "TesseractVault: insufficient weight for XCM");

        // Step 2 — CROSS-VM CALL (EVM → PVM)
        // This call crosses VM boundaries at the runtime level. The Hub runtime
        // dispatches it automatically — no bridge, no special encoding.
        uint64 bestIndex = 0;
        if (computeContract != address(0) && strategyAprs.length > 0) {
            bestIndex = ITesseractCompute(computeContract).getBestStrategy(strategyAprs);
        }

        // Step 3 — XCM EXECUTION
        // weighMessage prevents asset trapping on the destination chain.
        IXcm.Weight memory w = IXcm(xcmPrecompile).weighMessage(xcmMessage);
        IXcm(xcmPrecompile).execute(xcmMessage, w);

        emit Rebalanced(bestIndex, xcmMessage, w.refTime, w.proofSize);
    }

    // ──────────────────── Admin ────────────────────

    /// @notice Wire the PVM compute module after deployment. Can only be set once.
    function setComputeContract(address _compute) external onlyOwner {
        require(computeContract == address(0), "TesseractVault: already set");
        require(_compute != address(0), "TesseractVault: zero address");
        computeContract = _compute;
        emit ComputeContractSet(_compute);
    }
}

